import java.util.TreeSet;

class SummaryRanges {

    private TreeSet<Integer> set;

    public SummaryRanges() {
        set = new TreeSet<>();
    }

    public void addNum(int value) {
        set.add(value);
    }

    public int[][] getIntervals() {
        int[][] intervals = new int[set.size()][2];
        int i = 0;
        int start = -1;
        int end = -1;
        for (int num : set) {
            if (start == -1) {
                start = num;
                end = num;
            } else if (num == end + 1) {
                end = num;
            } else {
                intervals[i++] = new int[] {start, end};
                start = num;
                end = num;
            }
        }
        if (start != -1) {
            intervals[i++] = new int[] {start, end};
        }
        int[][] result = new int[i][2];
        System.arraycopy(intervals, 0, result, 0, i);
        return result;
    }
}
```

